VALUES
  ('social-worker-moex-07300', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究、典範（paradigm）與理論間關係之敘述中，下列何者正確？', '["典範與理論都能影響或指導研究之進行", "只有理論才能影響或指導研究之進行", "一個理論可能包含若干典範", "理論即典範，兩者可交替使用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07301', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在探討較複雜的因果關係之研究中，除了自變項和依變項外，還有所謂的中介變項。下列有關中介變項 的敘述中，何者正確？', '["自變項和依變項間，只可能有一個中介變項", "中介變項就是控制變項", "中介變項可視為自變項的依變項，也可視為依變項的自變項", "中介變項與自變項和依變項無關，它是另一種類型的變項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07302', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者並非實證主義研究典範下的觀點？', '["科學方法的邏輯只有一套，社會科學和自然科學間並無差異", "社會科學研究的目的在於了解，了解以便預測，預測以便控制", "社會科學研究要重視設身處地的理解，才能有效了解人類行為", "人們可藉由理性了解不理性的人類行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07303', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關敘述性統計的解釋，下列何者為非？', '["單變項分析的主要目的是在於解決變項間之關聯", "單變項分析是我們從大的母群總體抽出一部分作為樣本，描述這些研究單位在變項上的特質，試圖推 論到母群體的性質為何", "雙變項分析是包含兩個變數的分析", "單變項分析的目的是描述性的，而雙變項則包含了關係的分析"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07304', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關誤差敘述，何者為正確？', '["測量誤差是進行社會工作研究避免不了的狀態，所以我們不用花太多心思在上面，而應該儘量加大研 究樣本之數量", "系統性誤差指我們所蒐集到的資料，持續的反應某個受測驗概念的錯誤", "隨機誤差指因為我們抽樣太隨機，而導致之誤差", "系統性誤差指電腦分析工具（例如SPSS）因系統性故障而導致資料偏誤之情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07305', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '問卷的好壞，不僅在於其信度和效度，還要注意鑑別度的問題。為了增加問卷之鑑別力，在正式施測前， 都會先施行試測。以下敘述，何者正確？', '["試測時最好找專家學者來施測，這叫專家效度", "為了提高試測之準確度，一定要送贈品", "如果不是指導教授之要求，通常我們不會做試測，以免勞民傷財", "試測最客觀的目的是使研究者能辨識出那個題目的鑑別度高、那個較低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07306', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '理論可以用來解釋社會生活的面向，是一套具系統性關聯之陳述。當研究者從觀察開始，尋找觀察中之 模式，再從中找出暫時性之結論，我們稱之為：', '["歸納法", "演繹法", "觀察法", "研究方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07307', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '賈伯斯想要了解「某電腦公司附設養護型長照機構品牌建立之初探研究」，請問他最好使用甚麼研究方 法？', '["行動研究", "評估研究", "訪談研究", "口述歷史"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07308', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小恩的論文題目是「社工師職業生涯規劃與其工作滿足感之相關研究」，請問自變項是：', '["小恩", "職業生涯規劃", "工作滿足感", "相關研究"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07309', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '媽媽想了解兒子們對「平均數」的了解程度，於是出一份共五個單選題的測驗，每題答對得20分，答錯 則為0分，全對則得滿分100分。閱卷完畢後媽媽統計各題的答對率如下： 題號  一  二  三  四  五 答對率  80%  90%  80%  70%  60% 請問此次測驗的平均分數為何？', '["76分", "77分", "80分", "75分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "fa0e5e75537b", "answer_pdf_sha1": "c98daef16df0", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
